/**
 * Debug script for Match #16 — why do players stop attacking in late game?
 *
 * Usage: npx tsx test/debug_match16.mjs
 */
import { runGame } from '../frontend/src/engine/game.ts';
import { executeScript } from '../frontend/src/engine/script.ts';
import { createEntity, manhattan } from '../frontend/src/engine/entity.ts';

// ── Match #16 data ──
const SEED = 3636195692;

function pack(hp, atk, atkRange, speed, manaMax, skillEffect, skillPower) {
  return BigInt(hp) | (BigInt(atk) << 8n) | (BigInt(atkRange) << 16n) | (BigInt(speed) << 24n)
    | (BigInt(manaMax) << 32n) | (BigInt(skillEffect) << 40n) | (BigInt(skillPower) << 56n);
}

// Players from match 16
const STATS = [
  pack(12, 4, 3, 1, 6, 0x0200, 4),  // [0] BaBaTa - Thorns
  pack(21, 2, 1, 0, 4, 0x0002, 1),  // [1] Tempest - Disarm
  pack(11, 5, 2, 3, 3, 0x0100, 2),  // [2] Venom - Stealth
  pack(10, 5, 2, 1, 4, 0x0010, 4),  // [3] Blaze - Lifesteal
  pack(10, 5, 2, 2, 3, 0x0040, 4),  // [4] Shadow - Execute
  pack(17, 3, 1, 1, 3, 0x0200, 3),  // [5] Titan - Thorns
  pack(9, 6, 2, 3, 3, 0x0400, 3),   // [6] Storm - Critical
  pack(10, 2, 4, 1, 4, 0x0080, 3),  // [7] Frost - ManaBurn
];

const NAMES = ['BaBaTa', 'Tempest', 'Venom', 'Blaze', 'Shadow', 'Titan', 'Storm', 'Frost'];

// Script bytes (from chain)
function hexToBytes(hex) {
  hex = hex.replace('0x', '');
  const arr = new Uint8Array(hex.length / 2);
  for (let i = 0; i < arr.length; i++) arr[i] = parseInt(hex.slice(i * 2, i * 2 + 2), 16);
  return arr;
}

const SCRIPTS = [
  hexToBytes(''),  // BaBaTa
  hexToBytes(''),  // Tempest (script 1)
  hexToBytes(''),  // Venom (script 2)
  hexToBytes(''),  // Blaze (script 3)
  hexToBytes(''),  // Shadow (script 4)
  hexToBytes(''),  // Titan (script 5)
  hexToBytes(''),  // Storm (script 6)
  hexToBytes(''),  // Frost (script 7)
];

// ── Run engine and add debug at turn 30+ ──
const result = runGame(STATS, SCRIPTS, SEED);

console.log('=== Match #16 Debug ===\n');

// Show final result
console.log('=== Rankings ===');
for (let i = 0; i < result.rankings.length; i++) {
  const r = result.rankings[i];
  const status = r.deathTurn > 0 ? `died T${r.deathTurn}` : 'alive';
  console.log(`#${i+1} ${NAMES[r.idx]} | Kills: ${r.kills} | EXP: ${r.exp} | ${status}`);
}

console.log('\n=== Turns 28-40 Detail ===\n');

// Replay turns 28+ with detailed entity state
for (let ti = 1; ti < result.turns.length; ti++) {
  const turn = result.turns[ti];
  if (turn.turn < 28) continue;

  console.log(`--- Turn ${turn.turn} | Ring: ${turn.ringRadius} | Alive: ${turn.entities.filter(e => e.alive).length} ---`);

  // Show positions and state of alive entities
  for (const ent of turn.entities) {
    if (!ent.alive) continue;
    console.log(`  [${ent.idx}] ${NAMES[ent.idx]} pos=(${ent.x},${ent.y}) HP:${ent.currentHp}/${ent.hp} ATK:${ent.atk} Range:${ent.atkRange} Exp:${ent.exposure} Mana:${ent.mana}/${ent.manaMax} Status:0x${ent.statusFlags.toString(16)} BlinkCD:${ent.blinkCooldown}`);
  }

  // Show events
  for (const ev of turn.events) {
    const actor = NAMES[ev.actorIdx] ?? '?';
    const target = ev.targetIdx != null ? NAMES[ev.targetIdx] : '';
    switch (ev.type) {
      case 'move': console.log(`  >> ${actor} MOVE to (${ev.toX},${ev.toY})`); break;
      case 'blink': console.log(`  >> ${actor} BLINK to (${ev.toX},${ev.toY})`); break;
      case 'attack': console.log(`  >> ${actor} ATTACK ${target} dmg=${ev.damage}`); break;
      case 'skill': console.log(`  >> ${actor} SKILL on ${target} dmg=${ev.damage}`); break;
      case 'defend': console.log(`  >> ${actor} DEFEND`); break;
      case 'idle': console.log(`  >> ${actor} IDLE`); break;
      case 'death': console.log(`  >> ${actor} DIES`); break;
      case 'kill': console.log(`  >> ${actor} KILLS ${target}`); break;
      case 'ring_damage': console.log(`  >> ${actor} RING DMG ${ev.damage}`); break;
      case 'level_up': console.log(`  >> ${actor} LEVEL UP to ${ev.newLevel}`); break;
      default: console.log(`  >> ${actor} ${ev.type}`);
    }
  }

  // For turns 30+, manually run script for each alive entity to see what it decides
  if (turn.turn >= 30) {
    console.log('  --- Script Debug ---');
    const prevTurn = result.turns[ti - 1];
    // Rebuild entities from previous turn snapshot for script execution
    for (const ent of prevTurn.entities) {
      if (!ent.alive) continue;
      // Check visibility
      const visible = [];
      for (const other of prevTurn.entities) {
        if (other.idx === ent.idx || !other.alive) continue;
        if ((ent.statusFlags & 0x0004) !== 0) continue; // blind
        if ((other.statusFlags & 0x0100) !== 0) continue; // stealth
        const dist = Math.abs(ent.x - other.x) + Math.abs(ent.y - other.y);
        if (dist <= ent.atkRange + other.exposure) {
          visible.push(`${NAMES[other.idx]}(dist=${dist},exp=${other.exposure})`);
        }
      }
      console.log(`  [${ent.idx}] ${NAMES[ent.idx]} at (${ent.x},${ent.y}) sees: [${visible.join(', ')}] (status=0x${ent.statusFlags.toString(16)})`);
    }
  }

  console.log('');
}
